import { AbstractControl, ValidationErrors, ValidatorFn } from '@angular/forms';

// Validator factory — returns a ValidatorFn
export function forbiddenNameValidator(forbidden: RegExp): ValidatorFn {
  return (control: AbstractControl): ValidationErrors | null => {
    const isForbidden = forbidden.test(control.value ?? '');
    return isForbidden ? { forbiddenName: { value: control.value } } : null;
  };
}

// Cross-field validator: passwords must match
export function passwordMatchValidator(
  control: AbstractControl
): ValidationErrors | null {
  const pw  = control.get('password')?.value;
  const pw2 = control.get('confirmPassword')?.value;
  return pw && pw2 && pw !== pw2 ? { passwordMismatch: true } : null;
}

// Using custom validators
form = new FormGroup(
  {
    username:        new FormControl('', [
      Validators.required,
      forbiddenNameValidator(/admin/i),   // no 'admin' usernames
    ]),
    password:        new FormControl('', [Validators.required, Validators.minLength(8)]),
    confirmPassword: new FormControl('', Validators.required),
  },
  { validators: passwordMatchValidator }  // group-level validator
);

