get usernameError() {
  const c = this.form.get('username');
  if (c?.errors?.['required'])      return 'Username is required.';
  if (c?.errors?.['forbiddenName']) return 'This username is not allowed.';
  return null;
}
get pwMismatch() { return this.form.errors?.['passwordMismatch']; }

import { Injectable } from '@angular/core';
import {
  AsyncValidator, AbstractControl, ValidationErrors
} from '@angular/forms';
import { Observable, of } from 'rxjs';
import { catchError, debounceTime, map, switchMap, take } from 'rxjs/operators';
import { UserService } from './user.service';

@Injectable({ providedIn: 'root' })
export class UniqueEmailValidator implements AsyncValidator {
  constructor(private users: UserService) {}

  validate(control: AbstractControl): Observable<ValidationErrors | null> {
    return of(control.value).pipe(
      debounceTime(400),                        // wait for typing to pause
      switchMap(email => this.users.checkEmail(email)),
      map(isTaken => (isTaken ? { emailTaken: true } : null)),
      catchError(() => of(null)),               // network errors = pass
      take(1)
    );
  }
}

// Inject validator and pass as third argument (asyncValidators)
constructor(private emailValidator: UniqueEmailValidator) {
  this.form = new FormGroup({
    email: new FormControl(
      '',
      [Validators.required, Validators.email],
      [this.emailValidator.validate.bind(this.emailValidator)]
    ),
  });
}

import { Component, inject } from '@angular/core';
import {
  FormArray, FormBuilder, FormControl,
  FormGroup, ReactiveFormsModule, Validators
} from '@angular/forms';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-skills-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  template: `
    <form [formGroup]="form" (ngSubmit)="onSubmit()">
      <label>Name <input formControlName="name" /></label>

      <fieldset formArrayName="skills">
        <legend>Skills</legend>
        @for (ctrl of skills.controls; track $index) {
          <div>
            <input [formControlName]="$index" placeholder="skill" />
            <button type="button" (click)="removeSkill($index)">✕</button>
          </div>
        }
        @empty { <p>No skills added yet.</p> }
      </fieldset>

      <button type="button" (click)="addSkill()">+ Add Skill</button>
      <button type="submit" [disabled]="form.invalid">Save</button>
    </form>
  `,
})
export class SkillsFormComponent {
  private fb = inject(FormBuilder);

  form = this.fb.group({
    name:   ['', Validators.required],
    skills: this.fb.array<FormControl<string>>([]),
  });

  get skills(): FormArray {
    return this.form.get('skills') as FormArray;
  }

  addSkill(): void {
    this.skills.push(this.fb.control('', Validators.required));
  }

  removeSkill(index: number): void {
    this.skills.removeAt(index);
  }

  onSubmit(): void {
    if (this.form.valid) console.log(this.form.value);
  }
}

import { TestBed } from '@angular/core/testing';
import { ReactiveFormsModule } from '@angular/forms';
import { LoginFormComponent } from './login-form.component';

describe('LoginFormComponent (unit)', () => {
  let component: LoginFormComponent;

  beforeEach(() => {
    TestBed.configureTestingModule({
      imports: [ReactiveFormsModule, LoginFormComponent],
    });
    component = TestBed.createComponent(LoginFormComponent).componentInstance;
  });

  it('should be invalid when empty', () => {
    expect(component.form.valid).toBeFalse();
  });

  it('should reject a badly formed email', () => {
    component.form.get('email')?.setValue('not-an-email');
    component.form.get('password')?.setValue('secret123');
    expect(component.form.get('email')?.errors?.['email']).toBeTrue();
    expect(component.form.valid).toBeFalse();
  });

  it('should be valid with correct values', () => {
    component.form.setValue({ email: 'user@example.com', password: 'secret123' });
    expect(component.form.valid).toBeTrue();
  });

  it('should call the submit handler', () => {
    spyOn(component, 'onSubmit');
    component.form.setValue({ email: 'user@example.com', password: 'secret123' });
    component.onSubmit();
    expect(component.onSubmit).toHaveBeenCalled();
  });
});

